// Get available report dates from Walmart API response
const reportsResponse = $('Get Available Reports').first().json;
const availableDates = reportsResponse.availableApReportDates || [];

// Get already-processed dates from sync cursor
const cursorRows = $('Get Sync Cursor').all();
const meta = (cursorRows.length > 0) ? (cursorRows[0].json.metadata || {}) : {};
const processedReports = meta.processed_reports || [];
const processedSet = new Set(processedReports);

// Filter to only new, valid report dates
const newDates = availableDates
  .filter(d => /^\d{8}$/.test(d) && !processedSet.has(d))
  .sort((a, b) => {
    // MMDDYYYY → YYYYMMDD for sorting
    const toSort = d => d.slice(4) + d.slice(0, 4);
    return toSort(a).localeCompare(toSort(b));
  });

if (newDates.length === 0) {
  return [{ json: { _noNewReports: true } }];
}

return newDates.map(d => ({ json: { reportDate: d } }));

const zlib = require('zlib');

// Get report date from the loop item
const reportDate = $('Loop Reports').first().json.reportDate;

// Get binary ZIP data from download
const binaryData = $input.first().binary?.data;
if (!binaryData) throw new Error("No binary data received");
const buffer = Buffer.from(binaryData.data, 'base64');

// Parse ZIP to extract CSV
let csvText;
if (buffer[0] === 0x50 && buffer[1] === 0x4B && buffer[2] === 0x03 && buffer[3] === 0x04) {
  const compressionMethod = buffer.readUInt16LE(8);
  const compressedSize = buffer.readUInt32LE(18);
  const uncompressedSize = buffer.readUInt32LE(22);
  const filenameLength = buffer.readUInt16LE(26);
  const extraFieldLength = buffer.readUInt16LE(28);
  const dataOffset = 30 + filenameLength + extraFieldLength;

  if (compressionMethod === 0) {
    csvText = buffer.slice(dataOffset, dataOffset + uncompressedSize).toString('utf8');
  } else if (compressionMethod === 8) {
    csvText = zlib.inflateRawSync(buffer.slice(dataOffset, dataOffset + compressedSize)).toString('utf8');
  } else {
    throw new Error('Unsupported ZIP compression: ' + compressionMethod);
  }
} else {
  csvText = buffer.toString('utf8');
}

// CSV parser
function parseCSVLine(line) {
  const result = [];
  let current = '';
  let inQuotes = false;
  for (let i = 0; i < line.length; i++) {
    const c = line[i];
    if (c === '"') inQuotes = !inQuotes;
    else if (c === ',' && !inQuotes) { result.push(current); current = ''; }
    else current += c;
  }
  result.push(current);
  return result;
}

const lines = csvText.split('\n').filter(l => l.trim());
if (lines.length < 2) {
  return [{ json: { fees: [], reportDate, parsedRows: 0, matchedFees: 0 } }];
}

const headers = parseCSVLine(lines[0]);
const rows = [];
for (let i = 1; i < lines.length; i++) {
  const values = parseCSVLine(lines[i]);
  if (values.length < 10) continue;
  const row = {};
  headers.forEach((h, idx) => { row[h.trim()] = (values[idx] || '').trim(); });

  const orderNum = row['Walmart.com Order #'];
  if (!orderNum) continue;

  const poNum = row['Walmart.com PO #'] || '';
  const poLine = row['Walmart.com P.O. Line #'] || '1';
  rows.push({
    order_number: orderNum,
    po_number: poNum,
    transaction_type: row['Transaction Type'] || '',
    transaction_date: row['Transaction Date Time'] || '',
    sku: row['Partner Item ID'] || '',
    commission: Math.abs(parseFloat(row['Commission from Sale']) || 0),
    commission_rate: row['Commission Rate'] || '',
    transaction_key: `${poNum}_${poLine}`,
    gross_sales: parseFloat(row['Gross Sales Revenue']) || 0
  });
}

// Build order lookup from earlier Supabase fetch
const WM_CHANNEL_ID = '2da7e1e0-579e-4968-bdef-fa18492a6a86';
const orders = $('Get Walmart Orders').all().map(i => i.json);
const orderLookup = {};
for (const o of orders) { orderLookup[o.order_number] = o; }

// Build existing refs set for dedup
const existingFees = $('Get Existing Fee Refs').all().map(i => i.json);
const existingRefs = new Set(existingFees.map(r => r.external_ref));

// Group by order and build fee records
const byOrder = {};
for (const row of rows) {
  if (!byOrder[row.order_number]) byOrder[row.order_number] = [];
  byOrder[row.order_number].push(row);
}

const fees = [];
for (const [orderNum, txRows] of Object.entries(byOrder)) {
  const order = orderLookup[orderNum];
  if (!order) continue;

  for (const tx of txRows) {
    const extRef = `wm-${tx.transaction_key}-CommissiononProduct`;
    if (existingRefs.has(extRef)) continue;
    if (tx.commission === 0 && tx.transaction_type === 'SALE') continue;

    let incurredAt = new Date().toISOString();
    const dm = (tx.transaction_date).match(/(\d{2})\/(\d{2})\/(\d{4})/);
    if (dm) incurredAt = `${dm[3]}-${dm[1]}-${dm[2]}T00:00:00Z`;

    fees.push({
      order_id: order.id,
      channel_id: WM_CHANNEL_ID,
      fee_type: 'marketplace_commission',
      description: 'Commission on Product',
      amount: tx.commission,
      currency_code: 'USD',
      incurred_at: incurredAt,
      external_ref: extRef,
      metadata: {
        sku: tx.sku,
        report_date: reportDate,
        commission_rate: tx.commission_rate,
        transaction_key: tx.transaction_key,
        transaction_type: tx.transaction_type
      }
    });
    existingRefs.add(extRef);
  }
}

return [{ json: { fees, reportDate, parsedRows: rows.length, matchedFees: fees.length } }];

// Build updated cursor with all processed report dates
const cursorRows = $('Get Sync Cursor').all();
const meta = (cursorRows.length > 0) ? (cursorRows[0].json.metadata || {}) : {};
const existingProcessed = meta.processed_reports || [];

const newReports = $('Filter New Reports').all()
  .filter(i => !i.json._noNewReports)
  .map(i => i.json.reportDate);

const allProcessed = [...new Set([...existingProcessed, ...newReports])];

return [{
  json: {
    source: 'walmart_fees',
    cursor_value: new Date().toISOString(),
    last_synced_at: new Date().toISOString(),
    records_synced: newReports.length,
    metadata: { processed_reports: allProcessed }
  }
}];
